import React, { useState, useMemo, useCallback } from 'react';
import { useInAppNavigate } from '../../../router/useInAppNavigate';

import { Input, SearchInput, dispatchAppToast, localInputToISOWithOffset } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { tscdService } from '../../../services/tscd/tscdService';
import { createFixedAssetSearchConfig } from '../../../components/search';
import { DocumentFormHeader } from '../../../components/layout';
import { UnsavedChangesModal } from '../../../components/form/UnsavedChangesModal';
import { useTscdOneShotFormGuard } from '../../../hooks/useTscdOneShotFormGuard';
import { tscdPageLabels } from '../../../constants/tscdPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { scrollToValidationTarget } from '../../../utils/scrollToValidationTarget';
import df from '../../../styles/documentForm.module.css';

const TEST_ID = 'tscd-thoi-khau-hao';
const labels = tscdPageLabels.thoiKhauHao;

const FIELD_ORDER = ['fixedAssetId', 'stopDate'] as const;
type FieldKey = (typeof FIELD_ORDER)[number];
type FieldErrors = Partial<Record<FieldKey, string>>;

function scrollToFirstError(errors: FieldErrors): void {
  const first = FIELD_ORDER.find(k => errors[k]);
  if (first) scrollToValidationTarget(`${TEST_ID}-field-${first}`);
}

const TscdThoiKhauHaoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useInAppNavigate();
  const assetSearchConfig = useMemo(() => createFixedAssetSearchConfig(), []);
  const { markDirty, showUnsavedModal, guardedAction, confirmLeave, cancelLeave } = useTscdOneShotFormGuard();
  const [fixedAssetId, setFixedAssetId] = useState('');
  const [assetCode, setAssetCode] = useState('');
  const [assetName, setAssetName] = useState('');
  const [stopDate, setStopDate] = useState(new Date().toISOString().slice(0, 10));
  const [note, setNote] = useState('');
  const [saving, setSaving] = useState(false);
  const [fieldErrors, setFieldErrors] = useState<FieldErrors>({});

  const patchFieldError = useCallback((key: FieldKey, value?: string) => {
    setFieldErrors(prev => {
      if (!value) {
        if (!(key in prev)) return prev;
        const next = { ...prev };
        delete next[key];
        return next;
      }
      return { ...prev, [key]: value };
    });
  }, []);

  const validate = (): FieldErrors => {
    const errors: FieldErrors = {};
    if (!fixedAssetId) errors.fixedAssetId = 'TSCĐ là bắt buộc';
    if (!stopDate) errors.stopDate = 'Ngày thôi KH là bắt buộc';
    return errors;
  };

  const handleSave = async () => {
    const errors = validate();
    if (Object.keys(errors).length > 0) {
      setFieldErrors(errors);
      scrollToFirstError(errors);
      dispatchAppToast(dispatch, { message: labels.validationSummary, type: 'error' });
      return;
    }
    setSaving(true);
    try {
      await tscdService.suspendDepreciation({
        fixedAssetId,
        stopDate: localInputToISOWithOffset(stopDate),
        note: note.trim() || undefined,
      });
      dispatchAppToast(dispatch, { message: labels.saveSuccess, type: 'success' });
      navigate('/tscd/danh-sach');
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, labels.saveError), type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={df.page} data-testid={`${TEST_ID}-form`}>
      <DocumentFormHeader
        onBack={() => guardedAction(() => navigate('/tscd/danh-sach'))}
        title={labels.title}
        isNew
        saving={saving}
        saveLabel={labels.saveLabel}
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>{labels.sectionTitle}</h2>
        <div className={df.row4}>
          <div className={df.spanCol2} id={`${TEST_ID}-field-fixedAssetId`} data-testid={`${TEST_ID}-field-fixedAssetId`}>
            <label className={df.label}>TSCĐ *</label>
            <SearchInput
              config={assetSearchConfig}
              value={fixedAssetId}
              primaryDisplay={assetCode}
              secondaryDisplay={assetName}
              onChange={a => {
                markDirty();
                setFixedAssetId(a.id);
                setAssetCode(a.code);
                setAssetName(a.name);
                patchFieldError('fixedAssetId');
              }}
              onClear={() => {
                markDirty();
                setFixedAssetId('');
                setAssetCode('');
                setAssetName('');
                patchFieldError('fixedAssetId');
              }}
              showLabel={false}
              error={fieldErrors.fixedAssetId}
            />
          </div>
          <div className={df.field} id={`${TEST_ID}-field-stopDate`} data-testid={`${TEST_ID}-field-stopDate`}>
            <label className={df.label}>Ngày thôi KH *</label>
            <Input
              type="date"
              value={stopDate}
              onChange={e => {
                markDirty();
                setStopDate(e.target.value);
                patchFieldError('stopDate');
              }}
              error={fieldErrors.stopDate}
              required
            />
          </div>
          <div className={df.field} data-testid={`${TEST_ID}-field-note`}>
            <label className={df.label}>Ghi chú</label>
            <Input value={note} onChange={e => { markDirty(); setNote(e.target.value); }} />
          </div>
        </div>
      </div>
      <UnsavedChangesModal
        isOpen={showUnsavedModal}
        onStay={cancelLeave}
        onLeave={confirmLeave}
      />
    </div>
  );
};

export default TscdThoiKhauHaoPage;
